    <g font-family="sans-serif">
      <text x="150" y="90" fill="#e4e4e7" font-size="13" text-anchor="middle" font-weight="700">Base</text>
      <rect x="180" y="76" width="460" height="26" rx="4" fill="#38bdf8"/>
